// The code below implements PROPER JWT verification as required for any production system.

const express = require('express');
const session = require('express-session');
const { Issuer, generators } = require('openid-client');
const jwt = require('jsonwebtoken');
const jwksClient = require('jwks-rsa');

const app = express();

// Session configuration
app.use(session({
  secret: require('crypto').randomBytes(32).toString('hex'),
  resave: false,
  saveUninitialized: false,
  cookie: {
    secure: process.env.NODE_ENV === 'production',
    httpOnly: true,
    sameSite: 'lax',
    maxAge: 3600000 // 1 hour
  }
}));

// Configuration - set these via environment variables
const CONFIG = {
  issuerUrl: process.env.OIDC_ISSUER_URL || 'https://accounts.google.com',
  clientId: process.env.OIDC_CLIENT_ID || 'your-client-id',
  clientSecret: process.env.OIDC_CLIENT_SECRET || 'your-client-secret',
  redirectUri: process.env.OIDC_REDIRECT_URI || 'http://localhost:3000/callback',
  port: process.env.PORT || 3000
};

let oidcClient;
let jwksClientInstance;

// Initialize OIDC client by discovering provider configuration
async function initializeOIDC() {
  try {
    const issuer = await Issuer.discover(CONFIG.issuerUrl);
    console.log('Discovered issuer:', issuer.issuer);

    oidcClient = new issuer.Client({
      client_id: CONFIG.clientId,
      client_secret: CONFIG.clientSecret,
      redirect_uris: [CONFIG.redirectUri],
      response_types: ['code'],
      token_endpoint_auth_method: 'client_secret_basic'
    });

    // Set up JWKS client for signature verification
    jwksClientInstance = jwksClient({
      jwksUri: issuer.metadata.jwks_uri,
      cache: true,
      cacheMaxEntries: 5,
      cacheMaxAge: 600000, // 10 minutes
      rateLimit: true,
      jwksRequestsPerMinute: 10
    });

    console.log('OIDC client initialized successfully');
  } catch (error) {
    console.error('Failed to initialize OIDC:', error);
    process.exit(1);
  }
}

// Get signing key for JWT verification
function getSigningKey(header) {
  return new Promise((resolve, reject) => {
    jwksClientInstance.getSigningKey(header.kid, (err, key) => {
      if (err) {
        reject(err);
        return;
      }
      const signingKey = key.getPublicKey();
      resolve(signingKey);
    });
  });
}

// SECURE: Verify and decode the ID token with full signature verification
async function verifyAndDecodeIdToken(idToken) {
  // First, decode the header to get the key ID (kid)
  const decodedHeader = jwt.decode(idToken, { complete: true });
  if (!decodedHeader) {
    throw new Error('Invalid JWT: unable to decode token header');
  }

  // Get the signing key from the JWKS endpoint
  const signingKey = await getSigningKey(decodedHeader.header);

  // Verify the token signature AND validate standard claims
  const verifiedClaims = jwt.verify(idToken, signingKey, {
    algorithms: ['RS256', 'RS384', 'RS512', 'ES256', 'ES384', 'ES512'],
    issuer: CONFIG.issuerUrl,
    audience: CONFIG.clientId,
    clockTolerance: 30 // 30 seconds tolerance for clock skew
  });

  return verifiedClaims;
}

// Extract user info from verified claims and create session data
function extractUserSessionData(claims) {
  return {
    sub: claims.sub,                    // Subject (unique user identifier)
    email: claims.email || null,
    emailVerified: claims.email_verified || false,
    name: claims.name || null,
    givenName: claims.given_name || null,
    familyName: claims.family_name || null,
    picture: claims.picture || null,
    locale: claims.locale || null,
    issuedAt: claims.iat,
    expiresAt: claims.exp,
    issuer: claims.iss,
    nonce: claims.nonce || null
  };
}

// Middleware to check if user is authenticated
function requireAuth(req, res, next) {
  if (req.session && req.session.user) {
    // Check if the token has expired
    const now = Math.floor(Date.now() / 1000);
    if (req.session.user.expiresAt && req.session.user.expiresAt < now) {
      req.session.destroy();
      return res.redirect('/login');
    }
    return next();
  }
  res.redirect('/login');
}

