// Initiate login - redirect to OpenID Provider
app.get('/login', (req, res) => {
  // Generate state and nonce for security
  const state = generators.state();
  const nonce = generators.nonce();

  // Store state and nonce in session for verification
  req.session.oidcState = state;
  req.session.oidcNonce = nonce;

  const authorizationUrl = oidcClient.authorizationUrl({
    scope: 'openid email profile',
    state: state,
    nonce: nonce,
    response_type: 'code'
  });

  res.redirect(authorizationUrl);
});

// Callback endpoint - handle the OIDC response
app.get('/callback', async (req, res) => {
  try {
    const { code, state, error, error_description } = req.query;

    // Check for errors from the provider
    if (error) {
      console.error('OIDC error:', error, error_description);
      return res.status(400).send(`Authentication error: ${escapeHtml(error_description || error)}`);
    }

    // Verify state parameter to prevent CSRF
    if (!state || state !== req.session.oidcState) {
      console.error('State mismatch - possible CSRF attack');
      return res.status(403).send('Invalid state parameter. Possible CSRF attack.');
    }

    if (!code) {
      return res.status(400).send('No authorization code received.');
    }

    // Exchange authorization code for tokens
    const params = oidcClient.callbackParams(req);
    const tokenSet = await oidcClient.callback(CONFIG.redirectUri, params, {
      state: req.session.oidcState,
      nonce: req.session.oidcNonce
    });

    console.log('Token set received. ID Token present:', !!tokenSet.id_token);

    if (!tokenSet.id_token) {
      return res.status(400).send('No ID token received from provider.');
    }

    // SECURE: Verify the JWT signature and validate claims
    // NEVER use jwt.decode() without verification in production!
    const verifiedClaims = await verifyAndDecodeIdToken(tokenSet.id_token);

    // Verify nonce matches to prevent replay attacks
    if (verifiedClaims.nonce && verifiedClaims.nonce !== req.session.oidcNonce) {
      console.error('Nonce mismatch - possible replay attack');
      return res.status(403).send('Invalid nonce. Possible replay attack.');
    }

    // Extract user data and create session
    const userSessionData = extractUserSessionData(verifiedClaims);

    // Clean up OIDC temporary session data
    delete req.session.oidcState;
    delete req.session.oidcNonce;

    // Set user session
    req.session.user = userSessionData;
    req.session.authenticatedAt = new Date().toISOString();

    console.log(`User authenticated: ${userSessionData.sub} (${userSessionData.email})`);

    // Redirect to home page
    res.redirect('/');

  } catch (error) {
    console.error('Callback error:', error.message);

    if (error.message.includes('invalid signature')) {
      return res.status(401).send('ID token signature verification failed. Token may be tampered with.');
    }
    if (error.message.includes('jwt expired')) {
      return res.status(401).send('ID token has expired.');
    }
    if (error.message.includes('jwt audience invalid')) {
      return res.status(401).send('ID token audience mismatch.');
    }
    if (error.message.includes('jwt issuer invalid')) {
      return res.status(401).send('ID token issuer mismatch.');
    }

    res.status(500).send('Authentication failed. Please try again.');
  }
});

